17→class FolderSettingsDescriptions {
18→    static final Map<String, TreeMap<Integer, SettingsDescription<?>>> SETTINGS;
19→    static final Map<Integer, SettingsUpgrader> UPGRADERS;
20→
21→    static {
22→        Map<String, TreeMap<Integer, SettingsDescription<?>>> s = new LinkedHashMap<>();
23→
24→        /*
25→         * When adding new settings here, be sure to increment {@link Settings.VERSION}
26→         * and use that for whatever you add here.
27→         */
28→
29→        s.put("displayMode", Settings.versions(
30→                new V(1, new EnumSetting<>(FolderClass.class, FolderClass.NO_CLASS)),
31→                new V(100, null)
32→        ));
33→        s.put("notifyMode", Settings.versions(
34→                new V(34, new EnumSetting<>(FolderClass.class, FolderClass.INHERITED)),
35→                new V(96, null)
36→        ));
37→        s.put("syncMode", Settings.versions(
38→                new V(1, new EnumSetting<>(FolderClass.class, FolderClass.INHERITED)),
39→                new V(99, null)
40→        ));
41→        s.put("pushMode", Settings.versions(
42→                new V(1, new EnumSetting<>(FolderClass.class, FolderClass.INHERITED)),
43→                new V(66, new EnumSetting<>(FolderClass.class, FolderClass.SECOND_CLASS)),
44→                new V(98, null)
45→        ));
46→        s.put("inTopGroup", Settings.versions(
47→                new V(1, new BooleanSetting(false))
48→        ));
49→        s.put("integrate", Settings.versions(
50→                new V(1, new BooleanSetting(false))
51→        ));
52→        s.put("notificationsEnabled", Settings.versions(
53→            new V(96, new BooleanSetting(false))
54→        ));
55→        s.put("pushEnabled", Settings.versions(
56→            new V(98, new BooleanSetting(false))
57→        ));
58→        s.put("syncEnabled", Settings.versions(
59→            new V(99, new BooleanSetting(false))
60→        ));
61→        s.put("visible", Settings.versions(
62→            new V(100, new BooleanSetting(true))
63→        ));
64→
65→        SETTINGS = Collections.unmodifiableMap(s);
66→
67→        // noinspection MismatchedQueryAndUpdateOfCollection, this map intentionally left blank
68→        Map<Integer, SettingsUpgrader> u = new HashMap<>();
69→        UPGRADERS = Collections.unmodifiableMap(u);
70→    }
71→
72→    static Map<String, Object> validate(int version, Map<String, String> importedSettings, boolean useDefaultValues) {
73→        return Settings.validate(version, SETTINGS, importedSettings, useDefaultValues);
74→    }
75→
76→    public static Map<String, String> convert(Map<String, Object> settings) {
77→        return Settings.convert(settings, SETTINGS);
78→    }
79→}
