400→    private fun SettingsImportUiModel.setGeneralSettingsImportStatus(
401→        importResults: ImportResults,
402→        importGeneralSettings: Boolean,
403→    ) {
404→        val importStatus = when {
405→            importResults.globalSettings -> ImportStatus.IMPORT_SUCCESS
406→            importGeneralSettings -> ImportStatus.IMPORT_FAILURE
407→            else -> ImportStatus.NOT_SELECTED
408→        }
409→        setSettingsListState(0, importStatus)
410→    }
