449→    private fun readSettings(contentUri: Uri): ImportContents {
450→        val inputStream = contentResolver.openInputStream(contentUri)
451→            ?: error("Failed to open settings file for reading: $contentUri")
452→
453→        return inputStream.use {
454→            settingsImporter.getImportStreamContents(inputStream)
455→        }
456→    }
