458→    private fun importSettings(contentUri: Uri, generalSettings: Boolean, accounts: List<AccountUuid>): ImportResults {
459→        val inputStream = contentResolver.openInputStream(contentUri)
460→            ?: error("Failed to open settings file for reading: $contentUri")
461→
462→        return inputStream.use {
463→            settingsImporter.importSettings(inputStream, generalSettings, accounts)
464→        }
465→    }
